command.text:
        /* <flatten type="Javascript"> */
var f = this, u = f.getItemValue('ma_loai_tb'), v1 = f.getItemValue('ngay_cuoi_thang_tu'), v2 = f.getItemValue('ngay_cuoi_thang_den'), v3 = f.getItemValue('ngay_cuoi_thang_bc');
if (u == '001' && !v1) if (f._checked) checkValue(f, 'c_tu_ngay');
if (u == '001' && !v2) if (f._checked) checkValue(f, 'c_den_ngay');
if (u != '001' && !v3) if (f._checked) checkValue(f, 'c_ngay_bc');
/* </flatten> */

script.text:
      &OutlineEntry;
      /* <flatten type="Javascript"> */
function active$NotifyList(f) {
  f.add_onResponseComplete(on$NotifyList$ResponseComplete);
  f.setItemValue('ma_loai_tb', f.grid._notifyType);
  setFormLayout(f, 1);
  onChange$Type$NotifyListFormDir(f);
}
function scatter$NotifyList(f) {
  f.setItemValue('ma_loai_tb', f.grid._notifyType);
  setFormLayout(f, 1);
  onChange$Type$NotifyListFormDir(f);
}
function close$NotifyList(f) {try {f.remove_onResponseComplete(on$NotifyList$ResponseComplete);} catch (ex) {}}
function on$NotifyList$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
     case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_tb');
      break;
    default:
      break;
  }
}
function setFormLayout(f, v) {
  if (f._action == 'View') return;

  var g = f.grid;
  var a = 'd_tu_ngay, c_tu_ngay, ngay_cuoi_thang_tu, c_tu_ngay_w, d_den_ngay, c_den_ngay, ngay_cuoi_thang_den, c_den_ngay_w, d_ngay_bc, c_ngay_bc, ngay_cuoi_thang_bc, c_ngay_bc_w, so_ngay, tk, ma_kh';

  if (f._action == 'New' || f._action == 'Edit') {
    setObjectFormHidden(f, 'd_ngay_bc, c_ngay_bc, ngay_cuoi_thang_bc, c_ngay_bc_w', g._notifyType == '002' || g._notifyType == '003' || g._notifyType == '004');
    setObjectFormHidden(f, 'd_tu_ngay, c_tu_ngay, ngay_cuoi_thang_tu, c_tu_ngay_w, d_den_ngay, c_den_ngay, ngay_cuoi_thang_den, c_den_ngay_w', g._notifyType == '001');

    setObjectFormHidden(f, 'so_ngay', g._$days);
    setObjectFormHidden(f, 'tk', g._$account);
    setObjectFormHidden(f, 'ma_kh', g._$customer);
  } else {
    setObjectFormHidden(f, a, v);
    setItemAllowNulls(f, a, v);
    if (f._$hide) {setObjectFormHidden(f, f._$hide, !v);}
  }
}

function onChange$Type$NotifyListFormDir(f){
  var t = f.getItemValue('type'), u = f.grid._notifyType;
  switch (u) {
    case '001':
      setItemDisable(f, 'd_tu_ngay, d_den_ngay', t != 0 || t == 2, true);
      setItemDisable(f, 'c_tu_ngay_w, c_den_ngay_w', t == 0 || t == 2, true);
      setItemDisable(f, 'ngay_cuoi_thang_tu, ngay_cuoi_thang_den', t == 0 || t == 1);

      setItemDisable(f, 'c_tu_ngay', f.getItemValue('ngay_cuoi_thang_tu') || t == 0 || t == 1, true);
      setItemDisable(f, 'c_den_ngay', f.getItemValue('ngay_cuoi_thang_den') || t == 0 || t == 1, true);
      setItemDisable(f, 'tk', false);

      setItemAllowNulls(f, 'd_ngay_bc, so_ngay', true);
      break;
    case '002':
      setItemDisable(f, 'd_ngay_bc', t != 0, true);
      setItemDisable(f, 'ngay_cuoi_thang_bc', t == 0 || t == 1);

      setItemDisable(f, 'c_ngay_bc', f.getItemValue('ngay_cuoi_thang_bc') || t == 0 || t == 1, true);
      setItemDisable(f, 'c_ngay_bc_w', t == 0 || t == 2, true);
      setItemDisable(f, 'tk, ma_kh', false);

      setItemAllowNulls(f, 'so_ngay', false);
      setItemAllowNulls(f, 'c_tu_ngay, d_tu_ngay, c_den_ngay, d_den_ngay', true);
      break;
    case '003':
      setItemDisable(f, 'd_ngay_bc', t != 0, true);
      setItemDisable(f, 'ngay_cuoi_thang_bc', t == 0 || t == 1);

      setItemDisable(f, 'c_ngay_bc', f.getItemValue('ngay_cuoi_thang_bc') || t == 0 || t == 1, true);
      setItemDisable(f, 'c_ngay_bc_w', t == 0 || t == 2, true);
      setItemDisable(f, 'tk, ma_kh', false);

      setItemAllowNulls(f, 'so_ngay', false);
      setItemAllowNulls(f, 'c_tu_ngay, d_tu_ngay, c_den_ngay, d_den_ngay', true);
      break;
    case '004':
      setItemDisable(f, 'd_ngay_bc', t != 0, true);
      setItemDisable(f, 'ngay_cuoi_thang_bc', t == 0 || t == 1);

      setItemDisable(f, 'c_ngay_bc', f.getItemValue('ngay_cuoi_thang_bc') || t == 0 || t == 1, true);
      setItemDisable(f, 'c_ngay_bc_w', t == 0 || t == 2, true);
      setItemDisable(f, 'tk', false);

      setItemAllowNulls(f, 'so_ngay, c_tu_ngay, d_tu_ngay, c_den_ngay, d_den_ngay', true);
      break;
    default:
      break;
  }
}
function setItemDisable(f, c, v, force) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      var o = f.getItem($func.trim(a[i]));
      if (o.a) $common.setVisible(o.a, !v);
      o.disabled = v;
      if(v) {
        switch (o.field.Type) {
          case 'DateTime':
            f.setItemValue($func.trim(a[i]), null);
            break;
          case 'Boolean':
            f.setItemValue($func.trim(a[i]), false);
            break;
          case 'String':
            o.value = '';
            break;
          case 'Decimal':
            f.setItemValue($func.trim(a[i]), 0);
            break;
          default:
            break;
        }
      }
    }
  }
  if (force) setItemAllowNulls(f, c, v);
}
function setItemAllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      o.field.AllowNulls = v
      if (o.a) $common.setVisible(o.a, !v);
      grandNode = o.parentNode.parentNode;
      if (!v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else {
        Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
        Sys.UI.DomElement.removeCssClass(grandNode, f._id);
      }
    }
  }
}
function setObjectFormHidden(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      grandNode = o.parentNode.parentNode;
      if (!v) $common.setVisible(o.parentNode.parentNode.parentNode, false);
    }
  }
}
function checkValue(f, field) {
  var a = field.split(','), t = f.getItemValue('type');
  for (var i = 0; i < a.length; i++) {
    var e = null, name = $func.trim(a[i]), o = f.getItem(name), c = o.value, l = o.field.Label;
    if (c.length > 0) {
      if (c.indexOf(',') >= 0) return showError(f, l, name);
      if (t == 2) if (c < 1 || c > 31) return showError(f, l, name);
    }
  }
  return true;
}
function showError(f, l, name) {
  var id = f.get_id(), msg = (f._language == 'v' ? 'Trường <span class="Highlight">{0}</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">{0}</span> must not be blank or has invalid value.');
  msg = String.format(msg, l);
  f._checked = false;
  $func.hideWait(id);
  $message.show(msg, String.format('$find(\'{0}\').getItem(\'' + name + '\').focus();', id));
  return false;
}
/* </flatten> */
      &ScriptIrregular;
